$ErrorActionPreference = "Stop"

# Detect company from hostname or domain
$system = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties()
$hostname = $system.HostName
$domain = $system.DomainName
if ([string]::IsNullOrWhiteSpace($domain)) {
    $isDomainJoined = $false
} else {
    $isDomainJoined = $true
}

# Dynamic company config
$CompanyConfig = @(
	@{ Name = "GCPL";	Domains = @("gainwellindia.com");			HostnamePatterns = @("GCPL") },
	@{ Name = "GEPL";	Domains = @("gainwellengineering.com");		HostnamePatterns = @("GEPL") },
	@{ Name = "RMSPL";	Domains = @();								HostnamePatterns = @("RMSPL") },
	@{ Name = "GTPL";	Domains = @();								HostnamePatterns = @("GTPL") },
	@{ Name = "ASPL";	Domains = @();								HostnamePatterns = @("ASPL") },
	@{ Name = "TIL";	Domains = @("tiplindia.com");				HostnamePatterns = @("TIL") }
)

# Company detection logic
$company = ""

# STEP 1: Prioritize hostname matching
foreach ($config in $CompanyConfig) {
    foreach ($pattern in $config.HostnamePatterns) {
        if ($hostname -match $pattern) {
            $company = $config.Name
            break
        }
    }
    if ($company) { break }
}

# STEP 2: Fallback to domain if hostname didn't match
if (-not $company -and $isDomainJoined) {
    foreach ($config in $CompanyConfig) {
        foreach ($knownDomain in $config.Domains) {
            if ($knownDomain.ToLower() -eq $domain.ToLower()) {
                $company = $config.Name
                break
            }
        }
        if ($company) { break }
    }
}

# ==================================
# REVERT OLD POLICY
# ==================================

# Specify the registry path
$registryPath = "Registry::HKEY_USERS"

# Get all keys under the specified path
$keys = Get-ChildItem -Path $registryPath

# Filter to include only users and exclude _Classes
$filteredKeys = $keys | Where-Object { $_.PSChildName -notlike "*_Classes" }

# Get user profiles to map SID to Username
$UserProfiles = Get-WmiObject Win32_UserProfile | Select-Object LocalPath, SID

foreach ($key in $filteredKeys) {
    $SID_Value = $key.PSChildName
    $subKey = "Registry::HKEY_USERS\$SID_Value"

    # Get corresponding username from user profile
    $UserProfile = $UserProfiles | Where-Object { $_.SID -eq $SID_Value }
    $UserName = if ($UserProfile) {
        ($UserProfile.LocalPath -split "\\")[-1] 
    } else { 
        "Unknown" 
    }

    # Check if registry path exists
    if (Test-Path $subKey) {
        try {
            # Define registry paths
            $photoViewerPath = "$subKey\Software\Microsoft\Windows Photo Viewer\Slideshow\Screensaver"
            $desktopPath = "$subKey\Control Panel\Desktop"
            $policyPath = "$subKey\Software\Policies\Microsoft\Windows\Control Panel\Desktop"
            $policy = "$subKey\Software\Microsoft\Windows\CurrentVersion\Policies\System"

            # Remove registry values
            Remove-ItemProperty -Path $desktopPath -Name "ScreenSaveTimeOut" -ErrorAction SilentlyContinue | Out-Null
            Remove-ItemProperty -Path $desktopPath -Name "ScreenSaveActive" -ErrorAction SilentlyContinue | Out-Null
            Remove-ItemProperty -Path $desktopPath -Name "ScreenSaverIsSecure" -ErrorAction SilentlyContinue | Out-Null
            Remove-ItemProperty -Path $desktopPath -Name "SCRNSAVE.EXE" -ErrorAction SilentlyContinue | Out-Null

            # Remove registry keys if they exist
            foreach ($path in @($photoViewerPath, $policyPath, $policy)) {
                if (Test-Path $path) {
                    Remove-Item -Path $path -Recurse -Force
                    #Write-Output "Removed registry key: $path"
                } else {
                    #Write-Output "Registry key not found: $path"
                }
            }

            #Write-Output "Registry settings reverted for user: $UserName"

        } catch {
            #Write-Output "Failed to revert settings for user: $UserName - Error: $_"
        }
    }
}

# ======================================================================================

# Proceed only if company is detected
if ($company) {

# ============================================================
# CONFIG
# ============================================================

$MainDir            = "C:\Windows\System32\Acceleron\"
$BaseDir            = Join-Path $MainDir "Screensaver"
$CertDir            = Join-Path $MainDir "Certificate"

$ScreensaverPath    = Join-Path $BaseDir "CorpSaver.scr"
$CertPath           = Join-Path $CertDir "GainwellWallpaper.cer"
$FolderPath         = "C:\Windows\Web\Screensaver"

$PinnedThumbprint   = "ECACA66CD84B620E80C8329A253DE85149666D6E"

$IsSystem           = ([Security.Principal.WindowsIdentity]::GetCurrent().IsSystem)
$IsAdmin            = ([Security.Principal.WindowsPrincipal] `
                      [Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)

# ============================================================
# ENSURE BASE DIRECTORY
# ============================================================

if (-not (Test-Path $BaseDir)) {
    New-Item -Path $BaseDir -ItemType Directory -Force | Out-Null
}

if (-not (Test-Path $CertDir)) {
    New-Item -Path $CertDir -ItemType Directory -Force | Out-Null
}

if (-not (Test-Path $FolderPath)) {
    New-Item -Path $FolderPath -ItemType Directory -Force | Out-Null
}

# ============================================================
# EMBEDDED BINARIES (BASE64)
# ============================================================

$CertBase64 = @'

'@

$ScreensaverBase64 = @'

'@

# ============================================================
# DECODE Screensaver
# ============================================================

$ScreensaverBytes = [Convert]::FromBase64String($ScreensaverBase64)

# ============================================================
# WRITE + TRUST CERTIFICATE (SYSTEM ONLY)
# ============================================================

if ($IsSystem -or $IsAdmin) {

    if (-not (Test-Path $CertPath)) {
        [IO.File]::WriteAllBytes(
            $CertPath,
            [Convert]::FromBase64String($CertBase64)
        )
    }

    foreach ($store in @(
        "Root",
        "TrustedPublisher"
    )) {
        if (-not (certutil -store $store | Select-String $PinnedThumbprint)) {
            & certutil.exe -addstore $store $CertPath | Out-Null
        }
    }
}

# ============================================================
# WRITE SCREENSAVER SCRIPT (SYSTEM)
# ============================================================
$WriteScreensaverExe = $true

if (Test-Path $ScreensaverPath) {

    $Sig = Get-AuthenticodeSignature $ScreensaverPath

    if (
        $Sig.SignerCertificate -and
        $Sig.SignerCertificate.Thumbprint -eq $PinnedThumbprint
    ) {
        $WriteScreensaverExe = $false
    }
}

if ($WriteScreensaverExe) {

    [IO.File]::WriteAllBytes($ScreensaverPath, $ScreensaverBytes)

    Start-Sleep 2
    $Sig = Get-AuthenticodeSignature $ScreensaverPath

    if (
        -not $Sig.SignerCertificate -or
        $Sig.SignerCertificate.Thumbprint -ne $PinnedThumbprint -or
        $Sig.Status -in @('HashMismatch','NotSigned')
    ) {
        throw "Screensaver signature validation failed"
    }
}

# ============================================================
# APPLY POLICY (SYSTEM)
# ============================================================

# Specify the registry path
$registryPath = "Registry::HKEY_USERS"

# Get all keys under the specified path
$keys = Get-ChildItem -Path $registryPath

# Filter to include only users and exclude _Classes
$filteredKeys = $keys | Where-Object { $_.PSChildName -notlike "*_Classes" }

# Get user profiles to map SID to Username
$UserProfiles = Get-CimInstance Win32_UserProfile | Select-Object LocalPath, SID

foreach ($key in $filteredKeys) {
    $SID_Value = $key.PSChildName
    $subKey = "Registry::HKEY_USERS\$SID_Value"

    # Get the corresponding username from user profile
    $UserProfile = $UserProfiles | Where-Object { $_.SID -eq $SID_Value }
    $UserName = if ($UserProfile) {
    ($UserProfile.LocalPath -split "\\")[-1] 
		} else { 
			"Unknown"
		}

    # Check if registry path exists
    if (Test-Path $subKey) {
        try {
            # Define registry paths
            $photoViewerPath = "$subKey\Software\Microsoft\Windows Photo Viewer\Slideshow\Screensaver"
            $desktopPath = "$subKey\Control Panel\Desktop"
            $policyPath = "$subKey\Software\Policies\Microsoft\Windows\Control Panel\Desktop"
            $policy = "$subKey\Software\Microsoft\Windows\CurrentVersion\Policies\System"

            # Create registry keys if they don't exist
            foreach ($path in @($photoViewerPath, $policyPath, $policy)) {
                if (-not (Test-Path $path)) {
                    New-Item -Path $path -Force | Out-Null
                }
            }
			
		    # Reset EncryptedPIDL (not needed for CorpSaver)
            if (Test-Path $photoViewerPath) {
                Remove-ItemProperty -Path $photoViewerPath -Name "EncryptedPIDL" -ErrorAction SilentlyContinue
            }
			
			# Optional cleanup
            Remove-ItemProperty -Path $photoViewerPath -Name "Speed" -ErrorAction SilentlyContinue

            # Set screensaver settings
			Set-ItemProperty -Path $photoViewerPath -Name "Delay" -Value ([int]60) -Type DWord
            Set-ItemProperty -Path $desktopPath -Name "ScreenSaveTimeOut" -Value 300 -Type String
            Set-ItemProperty -Path $desktopPath -Name "ScreenSaveActive" -Value 1 -Type String
            Set-ItemProperty -Path $desktopPath -Name "ScreenSaverIsSecure" -Value 1 -Type String
            Set-ItemProperty -Path $desktopPath -Name "SCRNSAVE.EXE" -Value $ScreensaverPath

            # Prevent users from changing screensaver settings
            Set-ItemProperty -Path $policyPath -Name "ScreenSaveActive" -Value 1 -Type String
            Set-ItemProperty -Path $policyPath -Name "SCRNSAVE.EXE" -Value $ScreensaverPath
            Set-ItemProperty -Path $policyPath -Name "ScreenSaverIsSecure" -Value 1 -Type String
            Set-ItemProperty -Path $policyPath -Name "ScreenSaveTimeOut" -Value 300 -Type String
            Set-ItemProperty -Path $policyPath -Name "NoChangingScreenSaver" -Value 1 -Type String

            # Disable the entire Screensaver settings dialog box
            Set-ItemProperty -Path $policy -Name "NoDispScrSavPage" -Value 1 -Type DWord

            # Prevent users from changing screensaver settings (this disables the "Settings" button)
            Set-ItemProperty -Path $policyPath -Name "ScreenSaverSettingsPage" -Value 1 -Type DWord

            Write-Output "Screensaver settings applied successfully for user: $UserName"
        } catch {
            Write-Output "Failed to apply settings for user: $UserName - Error: $_"
        }
    }
}

# Apply changes to user settings
RUNDLL32.EXE user32.dll, UpdatePerUserSystemParameters ,1 ,True

# Set Turn Off Display Timeout (in seconds)
powercfg /change monitor-timeout-dc 10		# 10 minutes on battery
powercfg /change monitor-timeout-ac 20		# 20 minutes when plugged in

# Set Sleep Timeout (in seconds)
powercfg /change standby-timeout-dc 60		# 1 hour on battery
powercfg /change standby-timeout-ac 0		# Never when plugged in

Write-Output "Power settings updated successfully!"

# Apply Group Policy
gpupdate /force | Out-Null

# Clear applied Certificate
Remove-Item $CertDir -Recurse -Force -ErrorAction SilentlyContinue

Write-Output "Screensaver settings applied successfully for all users!"

}
else {
    Write-Warning "Unable to detect company from domain or hostname. Please check the Hostname or Domain. Exiting..."
    exit 1
}
